arguments.new_str:
var builder = WebApplication.CreateBuilder(args);
builder.Services.AddScoped<IUserService, UserService>();
// Fix: CacheService is singleton but depended on scoped IUserService (captive dependency).
// .NET 9 enables ValidateScopes in development, which catches this at startup.
// Use a factory that resolves the scoped service per-call instead.
builder.Services.AddSingleton<ICacheService>(sp =>
    new CacheService(sp));
// Fix: .NET 9 HttpClientFactory uses SocketsHttpHandler by default;
// casting to HttpClientHandler throws InvalidCastException.
builder.Services.AddHttpClient("api")
    .ConfigurePrimaryHttpMessageHandler(() => new HttpClientHandler { UseCookies = false });
// Fix: .NET 9 ForwardedHeaders middleware ignores X-Forwarded-* from unknown proxies.
// Add your reverse proxy address to KnownProxies.
builder.Services.Configure<ForwardedHeadersOptions>(options =>
{
    options.ForwardedHeaders = ForwardedHeaders.XForwardedFor;
    options.KnownProxies.Add(System.Net.IPAddress.Parse("127.0.0.1"));
});
// Fix: .NET 9 HttpClientFactory redacts all header values in Trace-level logs.
// Allowlist specific non-sensitive headers you need to see.
builder.Services.ConfigureHttpClientDefaults(b =>
    b.RedactLoggedHeaders(h => h != "X-Request-Id" && h != "X-Correlation-Id"));
var app = builder.Build();
app.UseForwardedHeaders();
app.Run();

